import{_ as i,o as l,c as e,a2 as n}from"./chunks/framework.DZrHScmQ.js";const u=JSON.parse('{"title":"Known Drift Review","description":"","frontmatter":{},"headers":[],"relativePath":"projects/arti/playbooks/known-drift-review.md","filePath":"projects/arti/playbooks/known-drift-review.md"}'),o={name:"projects/arti/playbooks/known-drift-review.md"};function t(r,a,s,c,p,d){return l(),e("div",null,[...a[0]||(a[0]=[n(`<h1 id="known-drift-review" tabindex="-1">Known Drift Review <a class="header-anchor" href="#known-drift-review" aria-label="Permalink to &quot;Known Drift Review&quot;">​</a></h1><p><strong>状态：Draft</strong></p><p><strong>Owner：待指定</strong></p><p>用于处理 ARTI 跨仓共享标识、枚举、Prompt 和 DTO 漂移。</p><h2 id="适用场景" tabindex="-1">适用场景 <a class="header-anchor" href="#适用场景" aria-label="Permalink to &quot;适用场景&quot;">​</a></h2><p>两个以上 ARTI 仓库对同一业务对象、字符串值或数据形状解释不一致时使用。</p><p>典型对象：</p><ul><li><code>AnswerKind</code></li><li><code>NotificationKind</code></li><li>Report Type</li><li>Stock Symbol normalization</li><li>DTO <code>snake_case</code> / <code>camelCase</code></li><li>Prompt、Agent registry、report config</li></ul><h2 id="触发条件" tabindex="-1">触发条件 <a class="header-anchor" href="#触发条件" aria-label="Permalink to &quot;触发条件&quot;">​</a></h2><p>出现任一情况时，不继续单仓修改：</p><ol><li>改动会影响跨仓存储或传输值。</li><li>新 canonical 值尚未被消费者确认。</li><li>读取方依赖 alias、fallback 或历史兼容层。</li><li>生产数据已有多种表示。</li><li>文档、测试和代码命名不一致。</li></ol><h2 id="输入" tabindex="-1">输入 <a class="header-anchor" href="#输入" aria-label="Permalink to &quot;输入&quot;">​</a></h2><ul><li>Owner 和真源文件</li><li>生产者和消费者</li><li>主分支当前实现</li><li>生产或当前数据中的实际值</li><li>相关测试、RFC、契约、migration</li><li>已知 alias、fallback、兼容路径</li></ul><h2 id="步骤" tabindex="-1">步骤 <a class="header-anchor" href="#步骤" aria-label="Permalink to &quot;步骤&quot;">​</a></h2><ol><li>定义 canonical 值、含义和 Owner。</li><li>搜索所有生产者：server、Edge、Worker、CLI、migration、Prompt parser。</li><li>搜索所有消费者：读取、路由、展示、反序列化和兼容层。</li><li>设计兼容窗口：</li></ol><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>新增读取兼容</span></span>
<span class="line"><span>  → 收敛写入 canonical 值</span></span>
<span class="line"><span>  → 回填历史数据</span></span>
<span class="line"><span>  → 添加漂移检查</span></span>
<span class="line"><span>  → 删除 alias / fallback</span></span></code></pre></div><ul><li>增加固定用例：枚举集合、Symbol normalize、Report type 映射、Notification 路由、DTO 命名。</li><li>更新相关 Contract、Decision、README 或 RFC。</li></ul><h2 id="输出" tabindex="-1">输出 <a class="header-anchor" href="#输出" aria-label="Permalink to &quot;输出&quot;">​</a></h2><ul><li>canonical 值和 Owner</li><li>生产者 / 消费者清单</li><li>兼容策略和退出条件</li><li>测试或回读证据</li><li>遗留事项和负责人</li></ul><h2 id="完成标准" tabindex="-1">完成标准 <a class="header-anchor" href="#完成标准" aria-label="Permalink to &quot;完成标准&quot;">​</a></h2><ul><li>[ ] 生产者写入同一 canonical 值</li><li>[ ] 消费者兼容当前生产数据</li><li>[ ] alias / fallback 有退出条件</li><li>[ ] 契约和索引已同步</li><li>[ ] 有固定用例或自动检查防止再次漂移</li></ul><h2 id="停止与升级" tabindex="-1">停止与升级 <a class="header-anchor" href="#停止与升级" aria-label="Permalink to &quot;停止与升级&quot;">​</a></h2><p>以下情况升级为项目决策或事故处理：</p><ul><li>影响 Credits、结算、权限或数据完整性</li><li>无法确认生产真实值</li><li>两个以上仓库需要破坏性变更</li><li>Owner 不明确</li><li>兼容窗口没有退出条件</li></ul>`,24)])])}const f=i(o,[["render",t]]);export{u as __pageData,f as default};
